import React from 'react';
import ReactDOM from "react-dom";
import http from "./http-common";
import Select from 'react-select'
//import "./styles.css";

class FilterDropDown extends React.Component {
  // State with list of all checked item
   
   constructor(props) {
    super(props);
    this.state = {
      checked:[],
      optionsdata:[],
      checkList:[],
      checkedItems:""
    }
    //const [checked, setChecked] = useState([]);

   //this.checkList = ["Apple", "Banana", "Tea", "Coffee"];
   this.handleCheck = this.handleCheck.bind(this);
   this.retrieveData = this.retrieveData.bind(this);
  }
   

   handleCheck(event){


       this.props.parentCallback(event.value);

   } 

retrieveData(){
    const url = '/contacts.php?action=' + this.props.action

    const { page } = this.state;
     let params = {field: this.props.field};
     
    http.get(url,{params}).then(response => response.data)
    .then((data) => {
      let optionsdata = [];
      {Object.entries(data).map((keyname,index) => (
          optionsdata.push({label:keyname[1].name,value:keyname[1].term_id})
      ))}
      this.setState({ checkList: data, optionsdata :optionsdata })
      
     })
}
  
componentDidMount() {
    this.retrieveData();

}  

render(){
  

  return (
    <div className="app">
      
        
        <div className="list-container dropdowncontainer">
          
        <Select options={this.state.optionsdata} placeholder={this.props.title}  onChange={this.handleCheck}  />
            
              
              

              
        
      </div>
    </div>
  );
}
}
export default FilterDropDown;